struct Node* getNthFromEnd(struct Node *head, int n) {
    struct Node *first = head;
    struct Node *second = head;

    // Move first pointer n nodes ahead
    for(int i = 0; i < n; i++) {
        if(first == NULL) return NULL;  // n > length
        first = first->next;
    }

    // Move both until first reaches end
    while(first != NULL) {
        first = first->next;
        second = second->next;
    }

    return second;
}

// Example: List = 1->2->3->4->5, n=2
// Returns node with value 4 (2nd from end)

