def get_nth_from_end(self, n):
    first = second = self.head

    # Move first n nodes ahead
    for _ in range(n):
        if first is None:
            return None  # n > length
        first = first.next

    # Move both until first is None
    while first:
        first = first.next
        second = second.next

    return second.data if second else None

